#!/bin/bash
# ============================================================================
# start.sh — Template RunPod 1-CLICK: ComfyUI (Wan 2.2 I2V + Qwen-Image ger/edit)
# ----------------------------------------------------------------------------
# AUTOSSUFICIENTE: nao precisa de upload manual de nenhum arquivo.
# Cole este script inteiro no campo "Container Start Command" do template.
# No deploy ele instala tudo, baixa os modelos e sobe o servico sozinho.
#
# Imagem base esperada: runpod/pytorch:2.8.0-py3.11-cuda12.8.1-cudnn-devel-ubuntu22.04
# GPU alvo: RTX 5090 (Blackwell sm_120) ou superior, com 24GB+ de VRAM e CUDA 12.8.
# Portas HTTP: 8188 (ComfyUI) | 8888 (JupyterLab)
# Tempo de boot estimado: ~20-30 min (download de ~88GB de modelos: Wan + Qwen).
#
# QUALIDADE: o gerador Qwen roda no MODO CRU por padrao (20 steps / CFG 2.5,
# sem LoRA Lightning). Os 8 steps da Lightning degradavam a qualidade.
# Todos os workflows ja vem em 16:9 (imagens 1664x928, videos 832x480).
# ============================================================================
set -e
export DEBIAN_FRONTEND=noninteractive

# HuggingFace: desligar hf_transfer (deprecado/ausente) e usar XET (rapido e moderno)
unset HF_HUB_ENABLE_HF_TRANSFER
export HF_XET_HIGH_PERFORMANCE=1

mkdir -p /workspace/logs

# ----------------------------------------------------------------------------
# (0/6) JupyterLab: sobe logo no inicio, sem senha, para servir como ferramenta
# de debug em tempo real enquanto o resto do boot roda. A imagem base ja tem
# o pacote instalado; so precisamos iniciar.
# ----------------------------------------------------------------------------
echo "[boot] (0/6) Iniciando JupyterLab na porta 8888..."
nohup jupyter lab \
    --ip=0.0.0.0 --port=8888 --allow-root --no-browser \
    --ServerApp.token='' --ServerApp.password='' \
    --ServerApp.disable_check_xsrf=True \
    --ServerApp.allow_origin='*' \
    --ServerApp.allow_remote_access=True \
    --ServerApp.root_dir=/workspace \
    > /workspace/logs/jupyter.log 2>&1 &

echo "[boot] (1/6) Dependencias de sistema..."
apt-get update -qq
apt-get install -y -qq \
    ffmpeg \
    htop tmux build-essential lsof
pip install -q -U huggingface_hub hf_xet

# ----------------------------------------------------------------------------
# (2/6) ComfyUI + ComfyUI-Manager
#   IMPORTANTE: os clones sao condicionais (o volume /workspace persiste),
#   mas os "pip install" rodam SEMPRE. No RunPod o container e efemero:
#   ao recriar o pod com o mesmo volume, os pacotes pip somem, e sem
#   reinstalar o ComfyUI nao sobe. O pip e rapido quando ja esta tudo la.
# ----------------------------------------------------------------------------
if [ ! -d /workspace/ComfyUI ]; then
    echo "[boot] (2/6) Clonando ComfyUI..."
    cd /workspace
    git clone --depth 1 https://github.com/comfyanonymous/ComfyUI
fi
if [ ! -d /workspace/ComfyUI/custom_nodes/ComfyUI-Manager ]; then
    echo "[boot] (2/6) Clonando ComfyUI-Manager..."
    cd /workspace/ComfyUI/custom_nodes
    git clone --depth 1 https://github.com/ltdrdata/ComfyUI-Manager
fi
echo "[boot] (2/6) Instalando dependencias Python do ComfyUI..."
pip install -r /workspace/ComfyUI/requirements.txt
pip install -r /workspace/ComfyUI/custom_nodes/ComfyUI-Manager/requirements.txt || true
pip uninstall -y xformers 2>/dev/null || true   # vem na imagem base; incompativel com Blackwell

# ----------------------------------------------------------------------------
# (3/6) Modelos Wan 2.2 I2V 14B — versao fp8 (rapida) + LoRAs lightx2v 4steps
#       ~35GB total. fp8 e ~5x mais rapido que fp16 e cabe folgado na 5090.
# ----------------------------------------------------------------------------
if [ ! -f /workspace/ComfyUI/models/diffusion_models/wan2.2_i2v_high_noise_14B_fp8_scaled.safetensors ]; then
    echo "[boot] (3/6) Baixando modelos Wan 2.2 fp8 + LoRAs (~35GB)..."
    mkdir -p /workspace/_dl_stage
    mkdir -p /workspace/ComfyUI/models/{diffusion_models,text_encoders,vae,loras}
    python3 - << 'PYDL'
from huggingface_hub import hf_hub_download
REPO = 'Comfy-Org/Wan_2.2_ComfyUI_Repackaged'
files = [
    'split_files/diffusion_models/wan2.2_i2v_high_noise_14B_fp8_scaled.safetensors',
    'split_files/diffusion_models/wan2.2_i2v_low_noise_14B_fp8_scaled.safetensors',
    'split_files/loras/wan2.2_i2v_lightx2v_4steps_lora_v1_high_noise.safetensors',
    'split_files/loras/wan2.2_i2v_lightx2v_4steps_lora_v1_low_noise.safetensors',
    'split_files/text_encoders/umt5_xxl_fp8_e4m3fn_scaled.safetensors',
    'split_files/vae/wan_2.1_vae.safetensors',
]
for f in files:
    print('  baixando:', f.split('/')[-1])
    hf_hub_download(repo_id=REPO, filename=f, local_dir='/workspace/_dl_stage')
PYDL
    mv /workspace/_dl_stage/split_files/diffusion_models/*.safetensors /workspace/ComfyUI/models/diffusion_models/
    mv /workspace/_dl_stage/split_files/loras/*.safetensors            /workspace/ComfyUI/models/loras/
    mv /workspace/_dl_stage/split_files/text_encoders/*.safetensors    /workspace/ComfyUI/models/text_encoders/
    mv /workspace/_dl_stage/split_files/vae/*.safetensors              /workspace/ComfyUI/models/vae/
    rm -rf /workspace/_dl_stage
fi

# ----------------------------------------------------------------------------
# (4/6) Modelos Qwen-Image — GERADOR (2512, FP8, modo CRU por padrao) + EDITOR (2511, FP8 + Lightning 4-steps embutido).
#       Gerador: texto->imagem (cenas, paisagens, estilos). Roda SEM LoRA
#       Lightning por padrao (qualidade maxima). A LoRA 8-steps continua sendo
#       baixada apenas para o workflow carregar sem erro de modelo faltando;
#       ela vem DESLIGADA no workflow.
#       Editor: mantem o MESMO rosto e junta 2 personagens na mesma imagem.
#       Encoder e VAE sao COMPARTILHADOS com o gerador (baixados 1x so).
#       Custom node Comfyui-QwenEditUtils e obrigatorio para o editor.
#       ~53GB adicionais. Precisa de 24GB+ de VRAM (roda na 5090).
# ----------------------------------------------------------------------------
if [ ! -f /workspace/ComfyUI/models/diffusion_models/qwen_image_2512_fp8_e4m3fn.safetensors ]; then
    echo "[boot] (4/6) Baixando modelos Qwen-Image (gerador + editor)..."
    mkdir -p /workspace/_dl_qwen
    mkdir -p /workspace/ComfyUI/models/{diffusion_models,text_encoders,vae,loras}
    python3 - << 'PYBLOCK_QWEN'
from huggingface_hub import hf_hub_download

# Gerador 2512 + encoder + VAE (repo oficial Comfy-Org)
GEN_REPO = 'Comfy-Org/Qwen-Image_ComfyUI'
for f in [
    'split_files/diffusion_models/qwen_image_2512_fp8_e4m3fn.safetensors',
    'split_files/text_encoders/qwen_2.5_vl_7b_fp8_scaled.safetensors',
    'split_files/vae/qwen_image_vae.safetensors',
]:
    print('  [gerador]', f.split('/')[-1])
    hf_hub_download(repo_id=GEN_REPO, filename=f, local_dir='/workspace/_dl_qwen')

# (a LoRA Lightning do gerador e baixada em bloco proprio, mais abaixo)

# Editor 2511 (FP8 + Lightning 4-steps embutido)
print('  [editor] qwen_image_edit_2511_fp8_e4m3fn_scaled_lightning_comfyui_4steps_v1.0.safetensors')
hf_hub_download(repo_id='lightx2v/Qwen-Image-Edit-2511-Lightning',
    filename='qwen_image_edit_2511_fp8_e4m3fn_scaled_lightning_comfyui_4steps_v1.0.safetensors',
    local_dir='/workspace/_dl_qwen')
PYBLOCK_QWEN
    # Move tudo para as pastas certas (gerador + editor + compartilhados)
    find /workspace/_dl_qwen -name '*.safetensors' -path '*diffusion_models*' -exec mv -n {} /workspace/ComfyUI/models/diffusion_models/ \; 2>/dev/null || true
    find /workspace/_dl_qwen -name '*.safetensors' -path '*text_encoders*'    -exec mv -n {} /workspace/ComfyUI/models/text_encoders/ \;    2>/dev/null || true
    find /workspace/_dl_qwen -name '*.safetensors' -path '*vae*'              -exec mv -n {} /workspace/ComfyUI/models/vae/ \;              2>/dev/null || true
    find /workspace/_dl_qwen -name 'qwen_image_edit_2511*lightning*.safetensors' -exec mv -n {} /workspace/ComfyUI/models/diffusion_models/ \; 2>/dev/null || true
    rm -rf /workspace/_dl_qwen
fi

# LoRA Lightning 8-steps: checagem PROPRIA, separada do bloco acima.
# Motivo: em volumes /workspace antigos o bloco do Qwen nao roda (o modelo
# principal ja existe), entao a LoRA nova nunca seria baixada. Mesma licao
# dos pip installs: checar o arquivo especifico, nao o diretorio/modelo pai.
# NOTA: a LoRA vem DESLIGADA nos workflows (modo cru e o padrao). O arquivo
# so e baixado para o workflow nao acusar modelo faltando.
if [ ! -f /workspace/ComfyUI/models/loras/Qwen-Image-2512-Lightning-8steps-V1.0-fp32.safetensors ]; then
    echo "[boot] (4/6) Baixando LoRA Lightning 8-steps do Qwen (~1.7GB)..."
    mkdir -p /workspace/ComfyUI/models/loras
    python3 - << 'PYLORA8'
from huggingface_hub import hf_hub_download
hf_hub_download(repo_id='lightx2v/Qwen-Image-2512-Lightning',
    filename='Qwen-Image-2512-Lightning-8steps-V1.0-fp32.safetensors',
    local_dir='/workspace/_dl_lora8')
PYLORA8
    mv /workspace/_dl_lora8/Qwen-Image-2512-Lightning-8steps-V1.0-fp32.safetensors /workspace/ComfyUI/models/loras/
    rm -rf /workspace/_dl_lora8
fi

# Custom nodes: clone condicional (o volume persiste), pip install SEMPRE
# (mesmo motivo do passo 2/6: container efemero perde os pacotes pip).

# Comfyui-QwenEditUtils — obrigatorio para o workflow do EDITOR (no TextEncodeQwenImageEditPlus)
if [ ! -d /workspace/ComfyUI/custom_nodes/Comfyui-QwenEditUtils ]; then
    echo "[boot] (4/6) Clonando custom node Comfyui-QwenEditUtils..."
    cd /workspace/ComfyUI/custom_nodes
    git clone --depth 1 https://github.com/lrzjason/Comfyui-QwenEditUtils
fi

# WAS Node Suite — le prompts linha-a-linha (lote de imagem) e carrega imagens em sequencia (lote de video)
if [ ! -d /workspace/ComfyUI/custom_nodes/was-node-suite-comfyui ]; then
    echo "[boot] (4/6) Clonando custom node WAS Node Suite..."
    cd /workspace/ComfyUI/custom_nodes
    git clone https://github.com/WASasquatch/was-node-suite-comfyui.git
    git -C was-node-suite-comfyui checkout ea935d1044ae5a26efa54ebeb18fe9020af49a45 || true
fi

# VideoHelperSuite — componente de video (lote de video)
if [ ! -d /workspace/ComfyUI/custom_nodes/ComfyUI-VideoHelperSuite ]; then
    echo "[boot] (4/6) Clonando custom node VideoHelperSuite..."
    cd /workspace/ComfyUI/custom_nodes
    git clone https://github.com/Kosinkadink/ComfyUI-VideoHelperSuite.git
    git -C ComfyUI-VideoHelperSuite checkout 4ee72c065db22c9d96c2427954dc69e7b908444b || true
fi

echo "[boot] (4/6) Instalando dependencias Python dos custom nodes..."
for NODE in Comfyui-QwenEditUtils was-node-suite-comfyui ComfyUI-VideoHelperSuite; do
    REQ=/workspace/ComfyUI/custom_nodes/$NODE/requirements.txt
    [ -f "$REQ" ] && pip install -r "$REQ" || true
done

# ----------------------------------------------------------------------------
# (5/6) Workflows prontos na barra lateral do ComfyUI.
#       Ja vem ajustados (rosto fixo, lanczos, CLIP qwen_image, 16:9, modo cru).
#       Ao abrir o ComfyUI eles aparecem em "Workflows" > pasta do usuario,
#       a um clique cada, cada um abrindo em sua propria aba.
# ----------------------------------------------------------------------------
echo "[boot] (5/6) Instalando workflows prontos (Wan / Gerador / Editor / Lotes)..."
WF_DIR=/workspace/ComfyUI/user/default/workflows
mkdir -p "$WF_DIR"
cat > "$WF_DIR/1 - Video (Wan 2.2).json" << 'WORKFLOW_EOF_WAN'
{"id":"ec7da562-7e21-4dac-a0d2-f4441e1efd3b","revision":0,"last_node_id":9999,"last_link_id":246,"nodes":[{"id":97,"type":"LoadImage","pos":[90,250],"size":[610,490],"flags":{},"order":0,"mode":0,"inputs":[],"outputs":[{"name":"IMAGE","type":"IMAGE","slot_index":0,"links":[245]},{"name":"MASK","type":"MASK","slot_index":1,"links":null}],"title":"Start Frame Image","properties":{"cnr_id":"comfy-core","ver":"0.3.45","Node name for S&R":"LoadImage","ue_properties":{"widget_ue_connectable":{},"version":"7.7","input_ue_unconnectable":{}}},"widgets_values":["03_video_wan2_2_14B_i2v_subgraphed_input_image.png","image"]},{"id":108,"type":"SaveVideo","pos":[1300,250],"size":[680,530],"flags":{},"order":4,"mode":0,"inputs":[{"name":"video","type":"VIDEO","link":246}],"outputs":[],"properties":{"cnr_id":"comfy-core","ver":"0.3.49","Node name for S&R":"SaveVideo","ue_properties":{"widget_ue_connectable":{},"version":"7.7","input_ue_unconnectable":{}}},"widgets_values":["video/Wan2.2_image_to_video","auto","auto"]},{"id":118,"type":"MarkdownNote","pos":[-450,250],"size":[480,460],"flags":{},"order":1,"mode":0,"inputs":[],"outputs":[],"title":"Note: how to use this workflow","properties":{"ue_properties":{"widget_ue_connectable":{},"version":"7.7","input_ue_unconnectable":{}}},"widgets_values":["**Wan2.2 Image to Video(Subgraph)** node is a subgraph, which is converted from the Wan2.2 image to video workflow.\n\nYou can find the tutorial and original workflow [here](https://docs.comfy.org/tutorials/video/wan/wan2_2).\n\n\nThis workflow requires high VRAM (More than 20GB). If you are running this workflow locally, please make sure you have enough VRAM.\n\n## For Comfy Cloud users\n\nIf you are using [cloud.comfy.org](https://cloud.comfy.org/):\n\n1. Since the workflow in the Cloud will have the input image ready, for the first run, you can just click the run button to see what happens. \n\n2. Try to upload your own image to the **Start Frame Image**, and then try to describe the video you want to generate in the **Wan2.2 Image to Video(Subgraph)**."],"color":"#222","bgcolor":"#000"},{"id":119,"type":"MarkdownNote","pos":[-450,700],"size":[480,1070],"flags":{},"order":2,"mode":0,"inputs":[],"outputs":[],"title":"For local ComfyUI users","properties":{"ue_properties":{"widget_ue_connectable":{},"version":"7.1","input_ue_unconnectable":{}}},"widgets_values":["[Tutorial](https://docs.comfy.org/tutorials/video/wan/wan2_2\n)\n\n## VRAM Usage\n\nThe following data was tested using an RTX 4090 24GB\n\n| Model            | Size |VRAM Usage | 1st Generation | 2nd Generation |\n|---------------------|-------|-----------|---------------|-----------------|\n| fp8_scaled               |640*640| 84%               | ≈  536s              | ≈ 513s                   |\n| fp8_scaled +  4steps LoRA  | 640*640  | 83%                | ≈ 97s               | ≈ 71s                   |\n\n**Diffusion Model**\n- [wan2.2_i2v_high_noise_14B_fp8_scaled.safetensors](https://huggingface.co/Comfy-Org/Wan_2.2_ComfyUI_Repackaged/resolve/main/split_files/diffusion_models/wan2.2_i2v_high_noise_14B_fp8_scaled.safetensors)\n- [wan2.2_i2v_low_noise_14B_fp8_scaled.safetensors](https://huggingface.co/Comfy-Org/Wan_2.2_ComfyUI_Repackaged/resolve/main/split_files/diffusion_models/wan2.2_i2v_low_noise_14B_fp8_scaled.safetensors)\n\n**LoRA**\n- [wan2.2_i2v_lightx2v_4steps_lora_v1_low_noise.safetensors](https://huggingface.co/Comfy-Org/Wan_2.2_ComfyUI_Repackaged/resolve/main/split_files/loras/wan2.2_i2v_lightx2v_4steps_lora_v1_low_noise.safetensors)\n- [wan2.2_i2v_lightx2v_4steps_lora_v1_high_noise.safetensors](https://huggingface.co/Comfy-Org/Wan_2.2_ComfyUI_Repackaged/resolve/main/split_files/loras/wan2.2_i2v_lightx2v_4steps_lora_v1_high_noise.safetensors)\n\n**VAE**\n- [wan_2.1_vae.safetensors](https://huggingface.co/Comfy-Org/Wan_2.2_ComfyUI_Repackaged/resolve/main/split_files/vae/wan_2.1_vae.safetensors)\n\n**Text Encoder**   \n- [umt5_xxl_fp8_e4m3fn_scaled.safetensors](https://huggi